      "trust.c1.h": "Customer data stays customer data.",
      "trust.c2.h": "Everything is auditable.",
      "trust.c3.h": "The engineer signs.",
      "trust.c4.h": "The customer owns the data. Always.",
      "trust.c5.h": "Customer project data is not used to train models.",
      "trust.c6.h": "Regional data residency, configurable per tenant.",
      "trust.c7.h": "Enterprise SSO. Role-based access. Hardware-key support.",
      "trust.c8.h": "Encryption at rest. Encryption in transit. Per-tenant keys.",
      "trust.c9.h": "Logical isolation by default. Dedicated infrastructure on request.",
      "trust.c10.h": "From raw input to signed output, on one trail.",
      "trust.c11.h": "Cryptographic binding between document and signer.",
      "trust.c12.h": "Full forensic export available on request.",
      "trust.c13.h": "Building codes and engineering standards encoded as logic.",
      "trust.c14.h": "Data protection by design. DPA available.",
      "trust.c15.h": "Vendor onboarding ready for enterprise procurement.",
      "trust.c16.h": "Production uptime target.",
      "trust.c17.h": "How incidents are handled.",
      "trust.c18.h": "Backups and disaster recovery.",
      "trust.c19.h": "How vulnerabilities are managed.",
      "industries.uc1.h3": "Faster feasibility. Faster diligence.",
      "industries.uc1.body": "Developers buy automated feasibility studies, technical due diligence and climate-risk reports directly. Same regulatory compliance, fraction of the time.",
      "industries.uc2.h3": "Technical underwriting at portfolio scale.",
      "industries.uc2.body": "Lenders use Builtly for the technical-credit basis behind construction loans, for ongoing construction monitoring and for portfolio-risk analytics.",
      "industries.uc3.h3": "Portfolio screening, disclosure compliance.",
      "industries.uc3.body": "Asset managers and institutional investors use Builtly for portfolio-level technical and climate-risk diligence, including the disclosure obligations under TCFD and CSRD.",
      "industries.uc4.h3": "Procurement review, planning capacity.",
      "industries.uc4.body": "Public agencies use Builtly for automated tender-document review and for capacity-augmentation on planning work that internal teams cannot scale to meet.",
      "contact.h4.commercial": "Commercial",
