      "industries.aud01.head": "Eiendomsutviklere",
      "industries.aud01.h3": "Raskere mulighetsstudie. Raskere DD.",
      "industries.aud01.body": "Utviklere kjøper automatiserte mulighetsstudier, tekniske DD og klimarisikorapporter direkte. Bruken handler om beslutningshastighet: tomteoppkjøp går på stramme tidsfrister, og å vente flere uker på rådgiver-DD koster ofte handelen.",
      "industries.aud01.ml": "Typiske moduler",
      "industries.aud01.engagement.k": "Engasjement",
      "industries.aud01.engagement.v": "Direkte · per leveranse",
      "industries.aud02.h3": "Teknisk kredittvurdering i porteføljeskala.",
      "industries.aud02.body1": "Långivere bruker Builtly som teknisk grunnlag for byggelån, til løpende byggelånsoppfølging, og til klimarisiko på porteføljenivå mot rapporteringskrav. Volumet av beslutninger gjør manuell rådgivergjennomgang uøkonomisk.",
      "industries.aud02.body2": "Plattformen produserer strukturert output som integreres i kredittbeslutningssystemer og porteføljeoppfølging. White-label og API tilgjengelig for storbrukere.",
      "industries.aud02.ml": "Typiske moduler",
      "industries.aud02.engagement.k": "Engasjement",
      "industries.aud02.engagement.v": "Direkte · API · white-label",
      "industries.aud03.h3": "Porteføljescreening og rapporteringskrav.",
      "industries.aud03.body1": "Kapitalforvaltere og institusjonelle investorer bruker Builtly til teknisk og klimarelatert porteføljescreening, bærekrafts-forundersøkelser, og strukturerte rapporteringsutganger som kreves under finanssektorens klimarisikoregulering.",
      "industries.aud03.body2": "Plattformen skalerer over tusenvis av eiendeler uten å skalere ekspertkapasitet. Resultater er reviderbare og strukturert for nedstrøms rapporteringssystemer.",
      "industries.aud03.ml": "Typiske moduler",
      "industries.aud03.engagement.k": "Engasjement",
      "industries.aud03.engagement.v": "Direkte · API-integrasjon",
      "industries.aud04.head": "Offentlig sektor",
      "industries.aud04.h3": "Anbudsgjennomgang og planleggingskapasitet.",
      "industries.aud04.body1": "Offentlige etater bruker Builtly til automatisert anbudsdokumentgjennomgang og til kapasitetsforsterkning på planleggingssøknader. Offentlig ingeniørkapasitet er begrenset globalt, og Builtly lukker deler av gapet uten netto nyansettelser.",
      "industries.aud04.body2": "Typisk engasjement går via en rådgiverpartner som har den offentlige kontrakten, med Builtly som underliggende produksjonslag. Direkte anskaffelse støttes i jurisdiksjoner hvor dette er tillatt.",
      "industries.aud04.ml": "Typiske moduler",
      "industries.aud04.engagement.k": "Engasjement",
      "industries.aud04.engagement.v": "Rådgiverpartner · direkte",
      "industries.uc.lede": "Konkrete scenarier hvor plattformen erstatter eller komprimerer arbeid som i dag tar en rådgiver flere uker. Mønsteret er konsistent på tvers av segmenter: en beslutning som krever teknisk underlag, en tidslinje som ikke tillater tradisjonell rådgivning, og en regulatorisk standard som leveransen må tilfredsstille uansett.",
      "industries.uc1.h4": "Tomteoppkjøp under tidspress.",
      "industries.uc1.buyer": "Eiendomsutvikler",
      "industries.uc1.outcome": "Fra uker til samme dag. Beslutningen flyttes fra antagelse til evidens før eksklusiviteten utløper.",
      "industries.uc1.delivery.v": "Auto + Reviewed",
      "industries.uc2.h4": "Byggelånskvalifisering i porteføljeskala.",
      "industries.uc2.buyer": "Bank / byggelånsgiver",
      "industries.uc2.outcome": "Volum som var uøkonomisk å gjennomgå manuelt blir rutine. Risiko kommer frem tidligere i lånesyklusen.",
      "industries.uc2.delivery.v": "Auto · API",
      "industries.uc3.h4": "Klimarisikoraportering i portefølje.",
      "industries.uc3.buyer": "Kapitalforvalter / institusjonell investor",
      "industries.uc3.outcome": "Etterlevelse i porteføljeskala uten rådgiverkostnader i porteføljeskala. Sporbarhet intakt for regulatorisk gjennomgang.",
      "industries.uc3.delivery.v": "Auto · API",
      "industries.uc4.h4": "Leveransehastighet for rådgivere.",
      "industries.uc4.buyer": "Rådgivende ingeniør",
      "industries.uc4.outcome": "Senioringeniørtid brukt på ingeniørfaglig dømmekraft, ikke på rapportformatering. Gjennomstrømming øker uten bemanningsvekst.",
      "industries.uc4.delivery.v": "Attested",
      "industries.uc5.h4": "Anbudsforberedelse under kapasitetspress.",
      "industries.uc5.body": "En offentlig infrastrukturetat har flere anbudspakker å gjennomgå enn intern ingeniørkapasitet tillater. Builtly produserer strukturert anbudsgjennomgangsdokumentasjon per innlevering, kjører konsistenssjekker på tvers av pakker, og flagger avvik for menneskelig vurdering. Rådgiverpartner håndterer attestering.",
      "industries.uc5.outcome": "Ingeniørflaskehalsen i etaten åpnes. Anskaffelseskadens akselereres uten å gå på akkord med gjennomgangskvaliteten.",
      "industries.uc5.delivery.v": "Reviewed",
      "lbl.delivery": "Leveranse",
      "industries.r1.name": "Plattformlisens",
      "industries.r1.desc": "For rådgivere",
      "industries.r1.body1": "Hovedengasjementsmodellen. En rådgiver lisensierer hele plattformen for bruk på tvers av ingeniørteam, med sete-basert tilgang for ingeniører og per-leveranse-prising på utganger. Implementering, jurisdiksjonell konfigurasjon og teamonboarding inkludert.",
      "industries.r1.body2": "Egnet for rådgivere med jevn leveransevolum på tvers av flere fag. Den mest økonomiske ruten i skala.",
      "industries.r1.pricing.k": "Pris",
