      "platform.s01.h2": "En plattform.<br/>Tre kommersiella nivåer.",
      "platform.s02.h2": "Centrala discipliner.",
      "platform.s03.h2": "Stödjande arbetsflöden.",
      "platform.s04.h2": "Tilläggsfunktioner.",
      "platform.s05.h2": "Tekniska<br/>grunder.",
      "platform.s06.h2": "Pröva plattformen.",
      "industries.hero.eyebrow": "Branscher vi betjänar",
      "industries.hero.h1": "Byggd för konsultprofessionen.<br/>Använd över hela branschen.",
      "industries.hero.lede": "Builtlys primära kund är ingenjörskonsulten — företagen som producerar signerade, regulerade leveranser. Plattformens automatiserade nivåer köps också direkt av aktörerna konsulterna betjänar: fastighetsutvecklare, långivare, kapitalförvaltare och offentlig sektor. <span class=\"serif\">En plattform. Flera vägar till marknaden.</span>",
      "industries.s01.label": "Primär",
      "industries.s01.tag": "Kunden allt är byggt för",
      "industries.s02.label": "Närliggande köpare",
      "industries.s02.tag": "Direkta kunder av automatiserade moduler",
      "industries.s03.label": "Användningsfall",
      "industries.s03.tag": "Konkreta scenarier över segment",
      "industries.s04.label": "Vägar",
      "industries.s04.tag": "Hur du engagerar",
      "industries.s05.label": "Kom igång",
      "industries.s05.tag": "Hitta rätt väg",
      "industries.s01.h2": "Byggd för konsultprofessionen.",
      "industries.s02.h2": "Närliggande segment.",
      "industries.s03.h2": "I praktiken.",
      "industries.s04.h2": "Tre vägar.",
      "industries.s05.h2": "Hitta rätt väg.",
      "about.hero.eyebrow": "Om Builtly Engineering",
      "about.hero.h1": "Skapad av entreprenörer.<br/>Byggd av ingenjörer.<br/>För ingenjörer.",
      "about.insight.quote": "”Builtly tillhandahåller startpunkten. <span class=\"accent\">Ingenjören tillhandahåller ingenjörsarbetet.</span>”",
      "about.hero.lede": "Builtly Engineering är konvergensen av tre ovanliga discipliner under ett tak: professionellt ingenjörsansvar, kapitalmarknadserfarenhet från fastigheter, och modern mjukvaruutveckling. <span class=\"serif\">Det är inte slumpartat. Det är förutsättningen.</span>",
      "about.s01.label": "I korthet",
      "about.s01.tag": "Företaget i siffror",
      "about.s02.label": "Tes",
