      "industries.aud01.head": "Ejendomsudviklere",
      "industries.aud01.h3": "Hurtigere forundersøgelse. Hurtigere DD.",
      "industries.aud01.body": "Udviklere køber automatiserede forundersøgelser, teknisk due diligence og klimarisiko-rapporter direkte. Brugsscenariet handler om beslutningshastighed: grundkøb foregår på stramme tidslinjer, og at vente uger på en rådgiver-DD koster ofte handlen.",
      "industries.aud01.ml": "Typiske moduler",
      "industries.aud01.engagement.k": "Engagement",
      "industries.aud01.engagement.v": "Direkte · per leverance",
      "industries.aud02.h3": "Teknisk kreditvurdering i porteføljeskala.",
      "industries.aud02.body1": "Långivere bruger Builtly som teknisk kreditgrundlag bag byggelån, til løbende byggelånsopfølgning, og til klimarisiko på porteføljeniveau mod rapporteringskrav. Volumen af beslutninger gør manuel rådgivergennemgang uøkonomisk.",
      "industries.aud02.body2": "Platformen producerer strukturerede udgange der integreres i kreditbeslutningssystemer og porteføljeopfølgnings-dashboards. White-label og API-muligheder tilgængelige for storvolumskøbere.",
      "industries.aud02.ml": "Typiske moduler",
      "industries.aud02.engagement.k": "Engagement",
      "industries.aud02.engagement.v": "Direkte · API · white-label",
      "industries.aud03.h3": "Porteføljescreening og rapporteringsoverholdelse.",
      "industries.aud03.body1": "Kapitalforvaltere og institutionelle investorer bruger Builtly til teknisk og klimarisiko-screening på porteføljeniveau, bæredygtighedscertificerings-forundersøgelser, og de strukturerede rapporteringsudgange der kræves under finanssektorens klimarisiko-regulering.",
      "industries.aud03.body2": "Platformen skalerer over tusinder af aktiver uden at skalere ekspertkapaciteten. Resultaterne er reviderbare og strukturerede til nedstrøms rapporteringssystemer.",
      "industries.aud03.ml": "Typiske moduler",
      "industries.aud03.engagement.k": "Engagement",
      "industries.aud03.engagement.v": "Direkte · API-integration",
      "industries.aud04.head": "Offentlig sektor",
      "industries.aud04.h3": "Udbudsgennemgang, planlægningskapacitet.",
      "industries.aud04.body1": "Offentlige myndigheder bruger Builtly til automatiseret udbudsdokument-gennemgang og til kapacitetsforstærkning på planlægningsansøgninger. Offentlig ingeniørkapacitet er globalt begrænset, og Builtly lukker en del af gabet uden at kræve nettonye ansættelser.",
      "industries.aud04.body2": "Typisk engagement går via en rådgiverpartner der holder den offentlige kontrakt, med Builtly som det underliggende produktionslag. Direkte indkøb understøttes i jurisdiktioner hvor det er tilladt.",
      "industries.aud04.ml": "Typiske moduler",
      "industries.aud04.engagement.k": "Engagement",
      "industries.aud04.engagement.v": "Rådgiverpartner · direkte",
      "industries.uc.lede": "Specifikke scenarier hvor platformen erstatter eller komprimerer arbejde der i dag tager en rådgiver uger. Mønstret er konsistent på tværs af segmenter: en beslutning der kræver teknisk underlag, en tidslinje der ikke tillader traditionel rådgivning, og en regulatorisk standard som udgangen skal opfylde uanset.",
      "industries.uc1.h4": "Grundkøb under tidspres.",
      "industries.uc1.buyer": "Ejendomsudvikler",
      "industries.uc1.outcome": "Fra uger til samme dag. Beslutningen flytter sig fra antagelse til evidens inden eksklusiviteten udløber.",
      "industries.uc1.delivery.v": "Auto + Reviewed",
      "industries.uc2.h4": "Byggelånsvurdering i porteføljeskala.",
      "industries.uc2.buyer": "Bank / byggelånsgiver",
      "industries.uc2.outcome": "Volumen der var uøkonomisk at gennemgå manuelt bliver rutine. Risiko bliver synlig tidligere i lånecyklussen.",
      "industries.uc2.delivery.v": "Auto · API",
      "industries.uc3.h4": "Klimarisiko-rapportering på porteføljeniveau.",
      "industries.uc3.buyer": "Kapitalforvalter / institutionel investor",
      "industries.uc3.outcome": "Overholdelse i porteføljeskala uden rådgiveromkostninger i porteføljeskala. Revisionsspor intakt til regulatorisk gennemgang.",
      "industries.uc3.delivery.v": "Auto · API",
      "industries.uc4.h4": "Leverancehastighed for rådgivningsfirmaer.",
      "industries.uc4.buyer": "Ingeniørrådgiver",
      "industries.uc4.outcome": "Senioringeniørtid brugt på ingeniørmæssig dømmekraft, ikke på rapportformatering. Gennemstrømning øges uden bemandingsudvidelse.",
      "industries.uc4.delivery.v": "Attested",
      "industries.uc5.h4": "Udbudsforberedelse under kapacitetsbegrænsning.",
      "industries.uc5.body": "En offentlig infrastrukturmyndighed har flere udbudspakker at gennemgå end intern ingeniørkapacitet tillader. Builtly producerer struktureret udbudsgennemgangs-dokumentation pr. indlevering, kører konsistenskontroller på tværs af pakker, og flagger afvigelser til menneskelig vurdering. Rådgiverpartneren håndterer attestering.",
      "industries.uc5.outcome": "Ingeniørflaskehalsen inde i myndigheden åbnes. Indkøbsrytmen accelereres uden at gå på kompromis med gennemgangskvaliteten.",
      "industries.uc5.delivery.v": "Reviewed",
      "lbl.delivery": "Leverance",
      "industries.r1.name": "Platformslicens",
      "industries.r1.desc": "Til rådgivningsfirmaer",
      "industries.r1.body1": "Den primære engagement-model. Et rådgivningsfirma licenserer hele platformen til brug på tværs af sine ingeniørteams, med sædebaseret adgang for ingeniører og per-leverance-prissætning på udgange. Implementering, jurisdiktionel konfiguration og teamonboarding inkluderet.",
      "industries.r1.body2": "Egnet til rådgivningsfirmaer med regelmæssig leverancevolumen på tværs af flere discipliner. Den mest økonomiske rute i skala.",
      "industries.r1.pricing.k": "Pris",
      "industries.r1.pricing.v": "Sæde + leverance",
      "industries.r1.onboarding.k": "Onboarding",
      "industries.r1.onboarding.v": "Samme uge",
      "industries.r1.minimum.k": "Minimum",
      "industries.r1.minimum.v": "3 sæder · 6 måneder",
      "industries.r2.name": "Direkte køb",
      "industries.r2.desc": "For slutkøbere",
      "industries.r2.body1": "Per-leverance-køb direkte fra portalen. Køberen uploader projektinput, vælger modul og leveranceniveau, og modtager udgangen i det foretrukne format. Ingen licens, ingen implementeringsomkostninger.",
      "industries.r2.body2": "Egnet til udviklere, långivere og kapitalforvaltere der køber auto-niveau-leverancer efter behov. Ingeniør-gennemgået og attesterede niveauer også tilgængelige hvor det kræves.",
      "industries.r2.pricing.v": "Per leverance",
      "industries.r2.onboarding.v": "Samme dag",
      "industries.r2.minimum.v": "Én leverance",
      "industries.r3.name": "Partnerintegration",
      "industries.r3.body2": "Egnet til storvolums-integrationer og hvor platformens udgange er input til en bredere arbejdsstrøm.",
      "industries.r3.pricing.v": "Forhandlet · volumen",
      "industries.r3.onboarding.v": "6–12 uger",
      "industries.r3.minimum.v": "Årlig forpligtelse",
      "industries.insight.accent": "Samme ingeniørmæssige stringens, uanset hvem der køber.",
      "industries.insight.lead": "Én platform, tre kommercielle veje.",
      "industries.insight.attr": "— Det kommercielle princip",
      "industries.cta.btn.open_portal": "Åbn portalen",
      "industries.cta.row.licence.k": "Platformslicens",
      "industries.cta.row.direct.k": "Direkte køb",
