      "trust.c1.h": "Asiakasdata pysyy asiakkaan datana.",
      "trust.c2.h": "Kaikki on tarkastettavissa.",
      "trust.c3.h": "Insinööri allekirjoittaa.",
      "trust.c4.h": "Asiakas omistaa datan. Aina.",
      "trust.c5.h": "Asiakas­projektidataa ei käytetä mallien koulutukseen.",
      "trust.c6.h": "Alueellinen datan sijainti, säädettävissä tenantia kohden.",
      "trust.c7.h": "Enterprise SSO. Roolipohjainen pääsy. Laitteistoavain-tuki.",
      "trust.c8.h": "Lepotilan salaus. Siirron salaus. Tenant-kohtaiset avaimet.",
