        "industries.r2.minimum.v": "Én leveranse",
        "industries.r3.name": "Partnerintegrasjon",
        "industries.r3.desc": "For plattformer og konsortier",
        "industries.r3.body1": "API-integrasjon eller white-label-løsning for partnere som bygger Builtly-funksjonalitet inn i egen arbeidsflyt — långiverportaler, proptech-plattformer, rådgivernettverk eller offentlige konsortier.",
        "industries.r3.body2": "Best for integrasjoner med høyt volum der Builtly-resultater blir del av en bredere kunde- eller beslutningsflyt.",
        "industries.r3.pricing.v": "Avtales · volum",
